// Premium Mock Product Database Registry with Stock Unsplash photography links
let PRODUCT_CATALOG = [
  { id: 1, title: "Apple iPhone 15 Pro Max (256 GB) - Natural Titanium", price: 139900, rating: "⭐ 4.6 (2,451 reviews)", img: "data:image/jpeg;base64," },
  { id: 2, title: "Sony WH-1000XM5 Wireless Premium Noise Cancelling Headphones", price: 29999, rating: "⭐ 4.5 (1,892 reviews)", img: "data:image/jpeg;base64," },
  { id: 3, title: "Apple MacBook Air Laptop M2 (13.6-inch, Liquid Retina Display)", price: 99900, rating: "⭐ 4.7 (3,102 reviews)", img: "data:image/jpeg;base64," },
  { id: 4, title: "Nike Air Max Premium Mens Cushion Sports Running Shoes", price: 8995, rating: "⭐ 4.2 (741 reviews)", img: "data:image/jpeg;base64," },
  { id: 5, title: "Casio Vintage Digital Minimalist Stainless Steel Casual Watch", price: 1695, rating: "⭐ 4.4 (5,810 reviews)", img: "data:image/jpeg;base64," },
  { id: 6, title: "American Tourister 32L Waterproof Professional Travel Backpack", price: 1899, rating: "⭐ 4.1 (930 reviews)", img: "data:image/jpeg;base64," }
];

let cart = [];

// DOM Element Selectors
const productGrid = document.getElementById('productGrid');
const searchInput = document.getElementById('searchInput');
const sectionTitle = document.getElementById('sectionTitle');
const cartDrawer = document.getElementById('cartDrawer');
const cartTrigger = document.getElementById('cartTrigger');
const closeDrawer = document.getElementById('closeDrawer');
const cartListing = document.getElementById('cartListing');
const globalCartCount = document.getElementById('globalCartCount');
const cartTotalPrice = document.getElementById('cartTotalPrice');
const addProductForm = document.getElementById('addProductForm');

// Core Catalog Rendering Engine with Filtering Capabilities
function renderCatalog(filterTerm = '') {
  productGrid.innerHTML = '';
  const query = filterTerm.toLowerCase().trim();
  
  // Filtering logic
  const filtered = PRODUCT_CATALOG.filter(p => p.title.toLowerCase().includes(query));
  
  // Set heading status title text based on condition
  sectionTitle.innerText = query ? `Showing results for "${filterTerm}"` : "Today's Deals & Special Offers";

  if (filtered.length === 0) {
    productGrid.innerHTML = `
      <div class="no-match">
        <h3>No verified results matching query bounds found.</h3>
        <p>Try searching for words like 'Apple', 'Sony', or 'Nike'.</p>
      </div>`;
    return;
  }

  filtered.forEach(product => {
    const card = document.createElement('div');
    card.className = 'product-card';
    card.innerHTML = `
      <div class="product-img-box">
        <img src="${product.img}" alt="${product.title}" onerror="this.src='https://unsplash.com'">
      </div>
      <h3 class="item-title">${product.title}</h3>
      <div class="rating-stars">${product.rating}</div>
      <div class="price-tag">₹${product.price.toLocaleString('en-IN')}</div>
      <button class="add-to-cart-btn" onclick="addToCart(${product.id})">Add to Cart</button>
    `;
    productGrid.appendChild(card);
  });
}

// Administrative Form Handler: Adds a Custom Product
addProductForm.addEventListener('submit', (e) => {
  e.preventDefault();
  
  const title = document.getElementById('prodTitle').value;
  const price = parseFloat(document.getElementById('prodPrice').value);
  const rating = document.getElementById('prodRating').value;
  let img = document.getElementById('prodImage').value;

  // Fallback URL if image field is left blank
  if (!img) {
    img = "https://unsplash.com";
  }

  const newProduct = {
    id: Date.now(), // Unique ID generation
    title: title,
    price: price,
    rating: rating + " (New)",
    img: img
  };

  PRODUCT_CATALOG.unshift(newProduct); // Push item to the top of the array
  renderCatalog(searchInput.value);    // Instantly update UI
  addProductForm.reset();             // Reset inputs
});

// Shopping Cart Mechanics Hub
window.addToCart = function(productId) {
  const product = PRODUCT_CATALOG.find(p => p.id === productId);
  const cartItem = cart.find(item => item.id === productId);
  
  if (cartItem) {
    cartItem.qty += 1;
  } else {
    cart.push({ ...product, qty: 1 });
  }
  updateCartUI();
};

window.removeCartItem = function(productId) {
  cart = cart.filter(item => item.id !== productId);
  updateCartUI();
};

function updateCartUI() {
  cartListing.innerHTML = '';
  let totalCount = 0;
  let totalPrice = 0;

  if (cart.length === 0) {
    cartListing.innerHTML = '<p style="text-align:center; color:#565959; margin-top:40px;">Your Amazon Basket is empty.</p>';
  } else {
    cart.forEach(item => {
      totalCount += item.qty;
      totalPrice += (item.price * item.qty);

      const row = document.createElement('div');
      row.className = 'cart-row';
      row.innerHTML = `
        <img class="row-thumb" src="${item.img}" alt="${item.title}">
        <div class="row-details">
          <p class="row-name">${item.title}</p>
          <p class="row-meta">${item.qty} x ₹${item.price.toLocaleString('en-IN')}</p>
        </div>
        <button class="trash-btn" onclick="removeCartItem(${item.id})">🗑️</button>
      `;
      cartListing.appendChild(row);
    });
  }

  globalCartCount.innerText = totalCount;
  cartTotalPrice.innerText = `₹${totalPrice.toLocaleString('en-IN')}`;
}

// Event Listeners for Interaction Handles
searchInput.addEventListener('input', (e) => renderCatalog(e.target.value));
cartTrigger.addEventListener('click', () => cartDrawer.classList.toggle('open'));
closeDrawer.addEventListener('click', () => cartDrawer.classList.remove('open'));

// Initialize Project Build on Window Mount
renderCatalog();
updateCartUI();
